import React from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { motion } from 'framer-motion';

const Landing = () => {
    const navigate = useNavigate();

    const handleRoleSelect = (role) => {
        navigate(`/login?role=${role}`);
    };

    return (
        <div className="auth-container" style={{ minHeight: '100vh', padding: '2rem' }}>
            <div className="auth-card glass-panel" style={{ maxWidth: '800px', margin: '0 auto', textAlign: 'center' }}>
                <div className="auth-header">
                    <div className="logo pulse-animation" style={{ fontSize: '5rem' }}>🏥</div>
                    <h1 className="gradient-text" style={{ fontSize: '3.5rem', marginBottom: '1rem' }}>Disease Predictor AI</h1>
                    <p style={{ fontSize: '1.2rem', color: '#718096', marginBottom: '3rem' }}>
                        Advanced AI-powered health analysis and disease prediction system.
                    </p>
                </div>

                <div className="grid-selection" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem', marginTop: '2rem' }}>
                    <div 
                        onClick={() => handleRoleSelect('patient')}
                        className="role-card card hover-scale" 
                        style={{ cursor: 'pointer', padding: '3rem', border: '2px solid #e2e8f0' }}
                    >
                        <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>👤</div>
                        <h2 style={{ color: '#2d3748' }}>Patient Portal</h2>
                        <p style={{ color: '#718096', fontSize: '0.9rem', marginTop: '1rem' }}>
                            Check symptoms, view history, and manage your health.
                        </p>
                        <button className="btn-primary" style={{ marginTop: '2rem', width: '100%' }}>Launch</button>
                    </div>

                    <div 
                        onClick={() => handleRoleSelect('doctor')}
                        className="role-card card hover-scale" 
                        style={{ cursor: 'pointer', padding: '3rem', border: '2px solid #e2e8f0' }}
                    >
                        <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🛡️</div>
                        <h2 style={{ color: '#2d3748' }}>Doctor Portal</h2>
                        <p style={{ color: '#718096', fontSize: '0.9rem', marginTop: '1rem' }}>
                            Analyze cohorts, manage patients, and view clinical data.
                        </p>
                        <button className="btn-secondary" style={{ marginTop: '2rem', width: '100%' }}>Launch</button>
                    </div>
                </div>

                <div style={{ marginTop: '3rem', color: '#a0aec0', fontSize: '0.8rem' }}>
                    &copy; 2026 Disease Predictor AI. All rights reserved.
                </div>
            </div>

            <style>{`
                .hover-scale { transition: all 0.3s ease; }
                .hover-scale:hover { transform: translateY(-10px); box-shadow: 0 20px 40px rgba(0,0,0,0.1); border-color: #667eea !important; }
                .grid-selection { grid-template-columns: 1fr 1fr; }
                @media (max-width: 600px) { .grid-selection { grid-template-columns: 1fr; } }
            `}</style>
        </div>
    );
};

export default Landing;
